/**
 * Routes a target descriptor to the matching {@link TicketIssuer}.
 * Open/closed: add a new (target × flow) combo by registering it here;
 * never edit existing branches.
 */
const TERMINAL_ISSUERS: Record<TerminalTarget['kind'], TicketIssuer<any>> = {
    'node': new NodeTermproxyIssuer(),
    'qemu': new QemuTermproxyIssuer(),
    'lxc': new LxcTermproxyIssuer(),
};

const VNC_ISSUERS: Record<VncTarget['kind'], TicketIssuer<any>> = {
    'node-shell': new NodeVncShellIssuer(),
    'qemu': new QemuVncproxyIssuer(),
    'lxc': new LxcVncproxyIssuer(),
};

function parseTicket(data: unknown): ConsoleTicket {
    if (data === null || typeof data !== 'object') {
        throw new Error('ticket payload is not an object');
    }
    const o = data as Record<string, unknown>;
    const ticket = String(o.ticket ?? '');
    const portRaw = o.port;
    const port =
        typeof portRaw === 'number' ? portRaw :
        typeof portRaw === 'string' ? parseInt(portRaw, 10) : NaN;
    if (!ticket || !Number.isFinite(port)) {
        throw new Error(`ticket payload missing required fields (ticket=${ticket} port=${portRaw})`);
    }
    return {
        ticket,
        port,
        user: String(o.user ?? ''),
        upid: typeof o.upid === 'string' ? o.upid : undefined,
        cert: typeof o.cert === 'string' ? o.cert : undefined,
    };
}

// ─────────────────────────────────────────────────────────────────────────────
// AuthAttacher (Strategy) — composes the auth headers the upgrade must
// carry. The vncticket query parameter is *not* session auth; the
// SDK's existing config (Cookie or API-token) authenticates the
// upgrade request itself.
// ─────────────────────────────────────────────────────────────────────────────

export interface AuthAttacher {
    headers(config: Configuration): Promise<Record<string, string>>;
}

export class CompositeAuthAttacher implements AuthAttacher {
    constructor(private readonly attachers: readonly AuthAttacher[]) {}
    async headers(config: Configuration): Promise<Record<string, string>> {
        const merged: Record<string, string> = {};
        for (const a of this.attachers) {
            Object.assign(merged, await a.headers(config));
        }
        return merged;
    }
}

class CookieAuthAttacher implements AuthAttacher {
    async headers(config: Configuration): Promise<Record<string, string>> {
        const apiKey = config.apiKey;
        if (!apiKey) return {};
        const value = typeof apiKey === 'function'
            ? await apiKey('PVEAuthCookie')
            : apiKey['PVEAuthCookie'];
        return value ? { Cookie: `PVEAuthCookie=${value}` } : {};
    }
}

class TokenAuthAttacher implements AuthAttacher {
    async headers(config: Configuration): Promise<Record<string, string>> {
        const apiKey = config.apiKey;
        if (apiKey) {
            const auth = typeof apiKey === 'function'
                ? await apiKey('Authorization')
                : apiKey['Authorization'];
            if (auth) return { Authorization: auth };
        }
        if (config.accessToken) {
            const token = typeof config.accessToken === 'function'
                ? await config.accessToken('PVEApiToken', [])
                : config.accessToken;
            if (token) return { Authorization: `PVEAPIToken=${token}` };
        }
        return {};
    }
}

const DEFAULT_AUTH = new CompositeAuthAttacher([
    new TokenAuthAttacher(),
    new CookieAuthAttacher(),
]);

// ─────────────────────────────────────────────────────────────────────────────
// WebSocketTransport (Adapter) — abstracts over the runtime WebSocket
// constructor so the rest of the helper depends only on the interface.
// ─────────────────────────────────────────────────────────────────────────────

export interface WebSocketTransport {
    open(url: string, headers: Record<string, string>): WebSocket;
}

class GlobalWebSocketTransport implements WebSocketTransport {
    open(url: string, headers: Record<string, string>): WebSocket {
        const Ctor = (globalThis as any).WebSocket;
        if (typeof Ctor !== 'function') {
            throw new Error('WebSocket is not available in this runtime. Use Node 18+ or a browser, or polyfill globalThis.WebSocket.');
        }
        if (Object.keys(headers).length === 0) return new Ctor(url);
        try {
            return new Ctor(url, undefined, { headers });
        } catch {
            return new Ctor(url);
        }
    }
}

const DEFAULT_TRANSPORT: WebSocketTransport = new GlobalWebSocketTransport();

// ─────────────────────────────────────────────────────────────────────────────
// UrlBuilder — single-responsibility helper that turns the SDK's
// configured `basePath` (https://host:port/api2/json) into the
// matching `wss://…/vncwebsocket?port=…&vncticket=…`.
// ─────────────────────────────────────────────────────────────────────────────

class UpgradeUrlBuilder {
    build(config: Configuration, basePath: string, ticket: ConsoleTicket): string {
        const wsBase = this.toWsScheme(config.basePath ?? 'https://localhost:8006/api2/json');
        const url = new URL(`${wsBase}${basePath}/vncwebsocket`);
        url.searchParams.set('port', String(ticket.port));
        url.searchParams.set('vncticket', ticket.ticket);
        return url.toString();
    }

    private toWsScheme(basePath: string): string {
        return basePath.replace(/^http(s?):/, (_, s) => `ws${s}:`);
    }
}

const DEFAULT_URL_BUILDER = new UpgradeUrlBuilder();

// ─────────────────────────────────────────────────────────────────────────────
// ConsoleConnector (Template Method) — the orchestrator. Single
// algorithm: issue ticket → build URL → attach auth → open socket →
// wrap session. Strategies plug in to vary the *what*, not the *how*.
// ─────────────────────────────────────────────────────────────────────────────

interface ConsoleConnectorDeps<T> {
    readonly issuer: TicketIssuer<T>;
    readonly auth: AuthAttacher;
    readonly transport: WebSocketTransport;
    readonly urlBuilder: UpgradeUrlBuilder;
}

abstract class ConsoleConnector<T, S> {
    constructor(protected readonly deps: ConsoleConnectorDeps<T>) {}

    async connect(config: Configuration, target: T, callbacks: SessionCallbacks): Promise<S> {
        const { ticket, basePath } = await this.deps.issuer.issue(config, target);
        const url = this.deps.urlBuilder.build(config, basePath, ticket);
        const headers = await this.deps.auth.headers(config);
        const socket = this.deps.transport.open(url, headers);
        // Wait for the WebSocket handshake to complete before returning.
        // PVE termproxy requires `<user>:<vncticket>\n` as the very
        // first frame after open; without it the daemon times out and
        // drops the connection. We must therefore (a) await `open` to
        // avoid racing the user's `send()`, and (b) push the in-band
        // auth before handing the session over.
        await new Promise<void>((resolve, reject) => {
            if ((socket as any).readyState === 1 /* OPEN */) return resolve();
            const onOpen = () => { cleanup(); resolve(); };
            const onError = (e: any) => { cleanup(); reject(e?.error ?? e); };
            const onClose = (e: any) => { cleanup(); reject(new Error(`WebSocket closed before open: ${e?.code ?? ''}`)); };
            const cleanup = () => {
                (socket as any).removeEventListener?.('open', onOpen);
                (socket as any).removeEventListener?.('error', onError);
                (socket as any).removeEventListener?.('close', onClose);
            };
            (socket as any).addEventListener?.('open', onOpen);
            (socket as any).addEventListener?.('error', onError);
            (socket as any).addEventListener?.('close', onClose);
        });
        if (this.needsInbandAuth()) {
            socket.send(`${ticket.user}:${ticket.ticket}\n`);
        }
        return this.wrap(socket, callbacks);
    }

    /** Override in subclasses that require the `<user>:<ticket>\n` first-frame handshake. */
    protected needsInbandAuth(): boolean {
        return false;
    }

    protected abstract wrap(socket: WebSocket, callbacks: SessionCallbacks): S;
}

// ─────────────────────────────────────────────────────────────────────────────
// Sessions — small classes that delegate framing to the codec; they
// own the lifecycle (heartbeat, close).
// ─────────────────────────────────────────────────────────────────────────────

const PING_INTERVAL_MS = 30_000;

abstract class BaseSession {
    protected closed = false;

    constructor(protected readonly socket: WebSocket) {}

    close(code = 1000, reason = 'client closed'): void {
        this.closed = true;
        this.onClose();
        if (this.socket.readyState === WebSocket.OPEN || this.socket.readyState === WebSocket.CONNECTING) {
            this.socket.close(code, reason);
        }
    }

    protected onClose(): void {
        // override
    }
}

export class TerminalSession extends BaseSession {
    private readonly codec = new TextFrameCodec();
    private readonly pinger: ReturnType<typeof setInterval> | null;
    private readonly inbound: { push(item: string): void };

    constructor(socket: WebSocket, callbacks: TerminalCallbacks) {
        super(socket);
        this.socket.binaryType = 'arraybuffer';
        this.inbound = { push: (msg: string) => callbacks.onMessage?.(msg) };
        this.socket.addEventListener('message', (ev) => this.codec.decodeChunk(ev.data, this.inbound));
        this.socket.addEventListener('close', (ev) => callbacks.onClose?.(ev as CloseEvent));
        this.socket.addEventListener('error', (ev) => callbacks.onError?.(ev));
        this.pinger = setInterval(() => this.maybeSend(TextFrameCodec.PING_FRAME), PING_INTERVAL_MS);
    }

    send(text: string): void {
        this.maybeSend(this.codec.encode(text));
    }

    resize(cols: number, rows: number): void {
        this.maybeSend(TextFrameCodec.encodeResize(cols, rows));
    }

    protected onClose(): void {
        if (this.pinger) clearInterval(this.pinger);
    }

    private maybeSend(payload: string | Uint8Array): void {
        if (this.socket.readyState !== WebSocket.OPEN) return;
        this.socket.send(payload as any);
    }
}

export class VncSession extends BaseSession {
    private readonly codec = new BinaryFrameCodec();
    private readonly inbound: { push(item: Uint8Array): void };

    constructor(socket: WebSocket, callbacks: VncCallbacks) {
        super(socket);
        this.socket.binaryType = 'arraybuffer';
        this.inbound = { push: (frame: Uint8Array) => callbacks.onFrame?.(frame) };
        this.socket.addEventListener('message', (ev) => this.codec.decodeChunk(ev.data, this.inbound));
        this.socket.addEventListener('close', (ev) => callbacks.onClose?.(ev as CloseEvent));
        this.socket.addEventListener('error', (ev) => callbacks.onError?.(ev));
    }

    send(data: Uint8Array): void {
        if (this.socket.readyState !== WebSocket.OPEN) return;
        this.socket.send(this.codec.encode(data));
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Concrete connectors — one per flow. Each picks the right
// {@link TicketIssuer} from the registry and the right session class.
// ─────────────────────────────────────────────────────────────────────────────

class TerminalConnector extends ConsoleConnector<TerminalTarget, TerminalSession> {
    constructor() {
        super({
            issuer: { issue: (cfg, t) => TERMINAL_ISSUERS[t.kind].issue(cfg, t) },
            auth: DEFAULT_AUTH,
            transport: DEFAULT_TRANSPORT,
            urlBuilder: DEFAULT_URL_BUILDER,
        });
    }
    protected needsInbandAuth(): boolean { return true; }
    protected wrap(socket: WebSocket, callbacks: SessionCallbacks): TerminalSession {
        return new TerminalSession(socket, callbacks as TerminalCallbacks);
    }
}

class VncConnector extends ConsoleConnector<VncTarget, VncSession> {
    constructor() {
        super({
            issuer: { issue: (cfg, t) => VNC_ISSUERS[t.kind].issue(cfg, t) },
            auth: DEFAULT_AUTH,
            transport: DEFAULT_TRANSPORT,
            urlBuilder: DEFAULT_URL_BUILDER,
        });
    }
    protected wrap(socket: WebSocket, callbacks: SessionCallbacks): VncSession {
        return new VncSession(socket, callbacks as VncCallbacks);
    }
}

const TERMINAL_CONNECTOR = new TerminalConnector();
const VNC_CONNECTOR = new VncConnector();

// ─────────────────────────────────────────────────────────────────────────────
// Public API — module-level functions that the Client facade delegates
// to. Compatibility surface for the rest of the SDK.
// ─────────────────────────────────────────────────────────────────────────────

export async function connectTerminal(
    config: Configuration,
    target: TerminalTarget,
    callbacks: TerminalCallbacks = {},
): Promise<TerminalSession> {
    return TERMINAL_CONNECTOR.connect(config, target, callbacks);
}

export async function connectVnc(
    config: Configuration,
    target: VncTarget,
    callbacks: VncCallbacks = {},
): Promise<VncSession> {
    return VNC_CONNECTOR.connect(config, target, callbacks);
}
